    <script nonce="">
      (() => {
        const tenant = "IONOS_US";

        const brand = "IONOS";
        const tld = "COM";

        const fallbackTenant = (brand && tld) ? `${brand}_${tld}` : null;

        const finalTenant = tenant ?? fallbackTenant;

        if (finalTenant) {
          const OAO = globalThis.OAO || {};
          OAO.q = OAO.q || {};
          OAO.q.c = OAO.q.c || [];
          OAO.q.c.push(['setTenant', finalTenant]);
        }
      })();
    </script>


    
